INSERT INTO CATEGORY (CATEGORY_CD, CATEGORY_NM) VALUES 
('INF_SEC', '정보처리기사'),
('SW_DEV', '소프트웨어 개발'),
('DB_CONST', '데이터베이스 구축');
INSERT INTO QUIZ_MASTER (CATEGORY_CD, QUESTION, OPTION_1, OPTION_2, OPTION_3, OPTION_4, ANSWER, EXPLANATION, LEVEL) VALUES
('INF_SEC', '소프트웨어 설계 중 인터페이스 요구사항 분석 시 고려사항이 아닌 것은?', '가용성', '무결성', '유지보수성', '상호운용성', 3, '인터페이스 요구사항 분석 시 가용성, 무결성, 상호운용성은 필수이나 유지보수성은 품질 특성에 가깝습니다.', 2),
('INF_SEC', '디자인 패턴 중 생성 패턴에 해당하지 않는 것은?', 'Abstract Factory', 'Builder', 'Prototype', 'Adapter', 4, 'Adapter 패턴은 구조 패턴에 해당합니다.', 2),
('INF_SEC', 'UML의 구조 다이어그램 중 하나로 시스템의 정적인 구조를 표현하는 것은?', '클래스 다이어그램', '시퀀스 다이어그램', '상태 다이어그램', '활동 다이어그램', 1, '클래스 다이어그램은 시스템의 정적 구조를 표현하는 대표적 도구입니다.', 1),
('INF_SEC', '결합도가 가장 낮은(가장 좋은) 것은?', '내용 결합도', '공통 결합도', '데이터 결합도', '제어 결합도', 3, '내공외제스자데 순으로 결합도가 낮아집니다.', 3),
('INF_SEC', '응집도가 가장 높은(가장 좋은) 것은?', '순차적 응집도', '기능적 응집도', '절차적 응집도', '우연적 응집도', 2, '우논시절통순기 순으로 응집도가 높아집니다.', 3),
('INF_SEC', '형상 관리의 절차로 옳은 것은?', '식별-통제-감사-기록', '기록-감사-통제-식별', '식별-감사-통제-기록', '기록-식별-감사-통제', 1, '형상 식별 후 통제, 감사, 상태 기록 순으로 진행됩니다.', 2),
('INF_SEC', '데이터베이스의 ACID 특성 중 하나로 트랜잭션의 연산은 모두 반영되거나 전혀 반영되지 않아야 함을 의미하는 것은?', '원자성', '일관성', '격리성', '영속성', 1, 'All or Nothing을 의미하는 것은 원자성(Atomicity)입니다.', 1),
('INF_SEC', '다음 중 스키마의 3계층에 해당하지 않는 것은?', '내부 스키마', '개념 스키마', '외부 스키마', '논리 스키마', 4, '3계층 스키마는 내부, 개념, 외부 스키마로 구성됩니다.', 1),
('INF_SEC', '관계 데이터베이스에서 튜플의 수를 의미하는 용어는?', '차수(Degree)', '카디널리티(Cardinality)', '도메인(Domain)', '속성(Attribute)', 2, '행의 수는 카디널리티, 열의 수는 차수입니다.', 2),
('INF_SEC', '화이트박스 테스트 기법이 아닌 것은?', '기초 경로 검사', '조건 검사', '루프 검사', '경계값 분석', 4, '경계값 분석은 블랙박스 테스트 기법입니다.', 2),
('INF_SEC', '애자일 개발 방법론이 아닌 것은?', 'XP', '스크럼', '폭포수 모델', '칸반', 3, '폭포수 모델은 고전적, 선형 순차적 모델입니다.', 1),
('INF_SEC', 'OSI 7계층 중 종단 간 신뢰성 있고 투명한 데이터 전송을 제공하는 계층은?', '물리 계층', '데이터 링크 계층', '네트워크 계층', '전송 계층', 4, '전송 계층은 TCP/UDP가 동작하는 신뢰성 전송 구간입니다.', 2),
('INF_SEC', 'TCP/IP 프로토콜 중 응용 계층에 해당하지 않는 것은?', 'HTTP', 'FTP', 'ICMP', 'DNS', 3, 'ICMP는 네트워크(인터넷) 계층 프로토콜입니다.', 3),
('INF_SEC', '프로세스 스케줄링 중 선점형 방식인 것은?', 'FIFO', 'SJF', 'Round Robin', 'HRN', 3, 'RR(Round Robin)은 대표적인 선점형 스케줄링입니다.', 2),
('INF_SEC', '교착상태 발생의 4가지 필요 충분 조건이 아닌 것은?', '상호 배제', '점유와 대기', '선점', '환형 대기', 3, '비선점이 조건이며, 선점은 발생 조건이 아닙니다.', 2),
('INF_SEC', 'C언어에서 변수 선언 시 사용할 수 없는 예약어는?', 'int', 'static', 'main', 'short', 3, 'main은 함수명으로 사용되는 식별자이지 변수 예약어가 아닙니다.', 2),
('INF_SEC', '데이터베이스 설계 순서로 옳은 것은?', '개념-논리-물리', '물리-논리-개념', '논리-개념-물리', '개념-물리-논리', 1, '개-논-물 순서로 설계가 진행됩니다.', 1),
('INF_SEC', '가상기억장치 구현 기법 중 고정된 크기로 나누어 관리하는 기법은?', '페이징', '세그먼테이션', '워킹셋', '스래싱', 1, '고정 크기는 페이징, 가변 크기는 세그먼테이션입니다.', 2),
('INF_SEC', '해싱 함수 중 키를 여러 부분으로 나누어 더하거나 XOR 하여 주소를 얻는 방식은?', '제산법', '폴딩법', '기수 변환법', '숫자 분석법', 2, '나누고 더하는 방식은 폴딩법(Folding)입니다.', 3),
('INF_SEC', '소프트웨어의 하위 설계에 해당하는 것은?', '아키텍처 설계', '인터페이스 설계', '모듈 설계', '데이터베이스 설계', 3, '상세 설계(하위 설계)는 모듈 및 컴포넌트 설계를 의미합니다.', 2);
INSERT INTO QUIZ_MASTER (CATEGORY_CD, QUESTION, OPTION_1, OPTION_2, OPTION_3, OPTION_4, ANSWER, EXPLANATION) VALUES
('SW_DEV', '21. 소프트웨어 프로젝트 관리에 대한 설명으로 가장 옳은 것은?', '개발에 따른 산출물 관리', '소요인력은 최대화하되 정책 결정은 신속하게 처리', '주어진 기간은 연장하되 최소의 비용으로 시스템을 개발', '주어진 기간 내에 최소의 비용으로 사용자를 만족시키는 시스템을 개발', 4, '소프트웨어 프로젝트 관리는 주어진 기간 내에 최소의 비용으로 사용자를 만족시키는 시스템을 개발하기 위한 전반적인 활동입니다.'),
('SW_DEV', '22. 개발한 소프트웨어가 사용자의 요구사항을 충족하는지에 중점을 두고 테스트하는 방법은?', '단위 테스트', '인수 테스트', '시스템 테스트', '통합 테스트', 2, '개발한 소프트웨어가 사용자의 요구사항을 충족하는지에 중점을 두고 테스트하는 방법을 인수 테스트(Acceptance Test)라고 합니다.'),
('SW_DEV', '23. 코드 인스펙션과 관련한 설명으로 틀린 것은?', '프로그램을 수행시켜보는 것 대신에 읽어보고 눈으로 확인하는 방법으로 볼 수 있다.', '코드 품질 향상 기법 중 하나이다.', '동적 테스트 시에만 활용하는 기법이다.', '결함과 함께 코딩 표준 준수 여부, 효율성 등의 다른 품질 이슈를 검사하기도 한다.', 3, '코드 인스펙션은 정적 테스트 시에만 활용하는 기법입니다.'),
('SW_DEV', '24. 다음 트리에 대한 중위 순회 운행 결과는?\n(트리 구조: A가 루트, A의 왼쪽 자식 B, 오른쪽 자식 C / B의 왼쪽 자식 D, 오른쪽 자식 E / C의 오른쪽 자식 F)', 'A B D C E F', 'A B C D E F', 'D B E C F A', 'D B A E C F', 4, '중위 순회(Inorder)는 Left → Root → Right \n이므로 D-B-E-A-C-F가 됩니다.'),
('SW_DEV', '25. 소프트웨어 개발에서 모듈(Module)이 되기 위한 주요 특징에 해당하지 않는 것은?', '다른 것들과 구별될 수 있는 독립적인 기능을 가진 단위(Unit)이다.', '독립적인 컴파일이 가능하다.', '유일한 이름을 가져야 한다.', '다른 모듈에서의 접근이 불가능해야 한다.', 4, '각 모듈들은 상호작용을 통해 더 큰 시스템을 구성해야 하므로 모듈은 상호 접근이 가능해야 합니다.'),
('SW_DEV', '26. 해시 함수가 서로 다른 키에 대해 같은 주소값을 반환해서 충돌이 발생하면 각 데이터를 해당 주소에 있는 링크드 리스트(Linked List)에 삽입하여 문제를 해결하는 기법은?', 'Chaining', 'Rehashing', 'Open Addressing', 'Linear Probing', 1, '체이닝(Chaining) : Collision이 발생하면 버킷에 할당된 연결 리스트(Linked List)에 데이터를 저장하는 방법'),
('SW_DEV', '27. 통합 개발 환경(IDE)에 대한 설명으로 옳지 않은 것은?', '프로그램 개발과 관련된 모든 작업을 하나의 프로그램에서 처리할 수 있도록 제공하는 소프트웨어적인 개발 환경을 말한다.', '통합 개발 환경 도구의 기능에는 코딩, 컴파일, 디버깅 등이 있다.', 'C, JAVA 등의 다양한 프로그래밍 언어로 프로그램을 작성하는 기능을 지원한다.', 'Python과 같은 인터프리터 언어로 프로그램을 작성하는 기능은 지원하지 않는다.', 4, '통합 개발 환경(IDE)은 Python과 같은 인터프리터 언어로 프로그램을 작성하는 기능도 지원합니다.'),
('SW_DEV', '28. 디지털 콘텐츠와 디바이스의 사용을 제한하기 위해 하드웨어 제조업자, 저작권자, 출판업자 등이 사용할 수 있는 접근 제어 기술을 의미하는 것은?', 'DRM', 'DLP', 'DOI', 'PKI', 1, '문제에서 설명하는 접근 제어 기술은 DRM(Digital Rights Management, 디지털 저작권 관리)입니다.'),
('SW_DEV', '29. 소프트웨어 설치 매뉴얼에 기본적으로 포함되어야 할 사항이 아닌 것은?', '소프트웨어 개요', '소프트웨어 설치 관련 파일', '소프트웨어 개발 비용', '소프트웨어 설치 및 삭제', 3, '소프트웨어 설치 매뉴얼의 기본적 포함 사항에는 소프트웨어 개요, 설치 관련 파일, 설치 아이콘, 프로그램 삭제, 관련 추가 정보 등이 있습니다.'),
('SW_DEV', '30. 개발 환경 구성을 위한 빌드(Build) 도구에 해당하지 않는 것은?', 'Ant', 'Kerberos', 'Maven', 'Gradle', 2, '빌드 자동화 도구에는 Ant, Make, Maven, Gradle, Jenkins 등이 있습니다.\nKerberos는 네트워크 인증 프로토콜의 하나입니다.'),
('SW_DEV', '31. 명세 기반 테스트 중 프로그램의 입력 조건에 중점을 두고, 어느 하나의 입력 조건에 대하여 타당한 값과 그렇지 못한 값을 설정하여 해당 입력 자료에 맞는 결과가 출력되는지 확인하는 테스트 기법은?', 'Cause-Effect Graphing Testing', 'Equivalence Partitioning Testing', 'Boundary Value Analysis', 'Comparison Testing', 2, '문제에 제시된 내용은 동치 분할 검사(Equivalence Partitioning Testing)에 대한 설명입니다.'),
('SW_DEV', '32. 내·외부 모듈 간 인터페이스 데이터 표준을 확인하는데 사용되는 정보로만 짝지어진 것은?', '인터페이스 목록, 인터페이스 명세', '인터페이스 명세, 데이터 인터페이스', '인터페이스 기능, 인터페이스 목록', '인터페이스 기능, 데이터 인터페이스', 4, '인터페이스 데이터 표준은 ''인터페이스 기능''과 ''데이터 인터페이스''를 통해 확인할 수 있습니다.'),
('SW_DEV', '33. 소프트웨어나 하드웨어의 오류나 잘못된 동작 등을 찾아 수정하는 기능은?', 'Coding', 'Compile', 'Debugging', 'Deployment', 3, '소프트웨어나 하드웨어의 오류나 잘못된 동작 등을 찾아 수정하는 기능은 디버깅(Debugging)입니다.'),
('SW_DEV', '34. 다음 설명에 해당하는 정렬(Sort)은?\n- 레코드의 많은 자료 이동을 없애고 하나의 파일을 부분적으로 나누어 가면서 정렬한다.\n- 분할(Divide)과 정복(Conquer)을 통해 자료를 정렬한다.\n- 피봇(pivot)을 사용하며, 최악의 경우 n(n-1)/2회의 비교를 수행해야 한다.', '힙 정렬', '퀵 정렬', '선택 정렬', '버블 정렬', 2, '문제의 지문에서 설명하는 정렬은 퀵 정렬(Quick Sort)입니다.'),
('SW_DEV', '35. 자료 구성 단위에 대한 설명으로 옳지 않은 것은?', '비트(Bit)는 0 또는 1을 표시하는 2진수 한 자리이다.', '니블(Nibble)은 네 개의 바이트가 모여 한 개의 니블을 구성한다.', '워드(Word)는 CPU가 처리할 수 있는 명령 단위이다.', '바이트(Byte)는 8개의 비트가 모여 1바이트를 구성한다.', 2, '니블(Nibble)은 4개의 비트(Bit)가 모여 1개의 니블을 구성합니다.'),
('SW_DEV', '36. 이진 트리의 레코드 R = (88, 74, 63, 55, 37, 25, 33, 19, 26, 14, 9)에 대하여 힙(Heap) 정렬을 만들 때, 37의 왼쪽과 오른쪽의 자노드(Child Node)의 값은?', '55, 25', '63, 33', '33, 19', '14, 9', 4, '힙 정렬은 자료를 전진 트리로 구성해 보면 간단하게 알 수 있습니다.\n(트리 상에서 37의 하위에 14와 9가 연결됨)'),
('SW_DEV', '37. 위험 관리의 일반적인 절차로 적합한 것은?', '위험 식별 → 위험 분석 및 평가 → 위험 관리 계획 → 위험 감시 및 조치', '위험 분석 및 평가 → 위험 식별 → 위험 관리 계획 → 위험 감시 및 조치', '위험 관리 계획 → 위험 감시 및 조치 → 위험 식별 → 위험 분석 및 평가', '위험 감시 및 조치 → 위험 식별 → 위험 분석 및 평가 → 위험 관리 계획', 1, '위험 관리의 일반적인 절차는 어떠한 위험이 있는지 먼저 식별하고, 그 위험을 분석한 후 이 위험을 어떻게 관리할 것인지 계획한 다음 위험에 대해 감시하고 조치를 취해야 합니다.'),
('SW_DEV', '38. 다음 중 소프트웨어를 재사용함으로써 얻는 이점이 아닌 것은?', '개발시간과 비용을 단축시킨다.', '소프트웨어 개발의 생산성을 높인다.', '프로젝트 실패의 위험을 줄여 준다.', '새로운 개발 방법론의 도입이 쉽다.', 4, '소프트웨어 재사용은 이미 개발된 인정받은 소프트웨어의 전체 혹은 일부분을 다른 소프트웨어 개발이나 유지에 사용하는 것으로 새로운 개발 방법론을 도입하기는 어렵습니다.'),
('SW_DEV', '39. 웹과 컴퓨터 프로그램에서 용량이 적은 데이터를 교환하기 위해 데이터 객체를 속성·값의 쌍 형태로 표현하는 형식으로, 자바 스크립트(JavaScript)를 토대로 개발되어진 형식은?', 'Python', 'XML', 'JSON', 'WEB SERVER', 3, '문제에 제시된 내용은 JSON(JavaScript Object Notation)에 대한 설명입니다.'),
('SW_DEV', '40. 다음 중 단위 테스트를 통해 발견할 수 있는 오류가 아닌 것은?', '알고리즘 오류에 따른 원치 않는 결과', '탈출구가 없는 반복문의 사용', '모듈 간의 비정상적 상호 작용으로 인한 원치 않는 결과', '틀린 계산 수식에 의한 잘못된 결과', 3, '단위 테스트는 모듈이나 컴포넌트 단위로 기능을 확인하는 테스트로, 모듈 간의 비정상적 상호 작용 오류 검사를 위해서는 통합 테스트를 수행해야 합니다.');
INSERT INTO QUIZ_MASTER (CATEGORY_CD, QUESTION, OPTION_1, OPTION_2, OPTION_3, OPTION_4, ANSWER, EXPLANATION) VALUES
('DB_CONST', '41. 트랜잭션의 특성을 모두 나열한 것은?\n㉠ Atomicity ㉡ Durability\n㉢ Transparency ㉣ Portability\n㉤ Consistency ㉥ Isolation', '㉠, ㉡', '㉠, ㉡, ㉥', '㉠, ㉢, ㉤', '㉠, ㉡, ㉤, ㉥', 4, '트랜잭션의 특성에는 Atomicity(원자성), Durability(영속성), Consistency(일관성), Isolation(독립성)이 있습니다.'),
('DB_CONST', '42. 학적 테이블에서 전화번호가 Null 값이 아닌 학생명을 모두 검색할 때, SQL 구문으로 옳은 것은?', 'SELECT 학생명 FROM 학적 WHERE 전화번호 DON''T NULL;', 'SELECT 학생명 FROM 학적 WHERE 전화번호 != NOT NULL;', 'SELECT 학생명 FROM 학적 WHERE 전화번호 IS NOT NULL;', 'SELECT 학생명 FROM 학적 WHERE 전화번호 IS NULL;', 3, 'NULL 값을 질의할 때는 IS NULL, NULL 값이 아닐 경우에는 IS NOT NULL을 사용합니다.'),
('DB_CONST', '43. 외래키에 대한 설명으로 옳지 않은 것은?', '외래키로 지정되면 참조 릴레이션의 기본키에 없는 값은 입력할 수 없다.', '다른 릴레이션의 기본키를 참조하는 속성 또는 속성들의 집합을 의미한다.', '참조되는 릴레이션의 기본키와 대응되어 릴레이션 간에 참조 관계를 표현하는데 중요한 도구이다.', '외래키는 유일성은 만족시키지만, 최소성은 만족시키지 못하므로 Null 값을 가질 수 없다.', 4, '유일성은 만족하지만 최소성을 만족하지 못하는 키는 슈퍼키에 대한 설명입니다.'),
('DB_CONST', '44. 다음 SQL 문장이 뜻하는 것은 무엇인가? (INSERT INTO 컴퓨터과테이블 SELECT 학번, 이름, 학년 FROM 학생테이블 WHERE 학과=''컴퓨터'')', '학생테이블에서 학과가 컴퓨터인 사람의 학번, 이름, 학년을 검색하라.', '학생테이블에 학과가 컴퓨터인 사람의 학번, 이름, 학년을 삽입하라.', '학생테이블에서 학과가 컴퓨터인 사람의 학번, 이름, 학년을 검색하여 컴퓨터과테이블에 삽입하라.', '컴퓨터과테이블에서 학과가 컴퓨터인 사람의 학번, 이름, 학년을 검색하여 학생테이블에 삽입하라.', 3, 'SELECT문을 통해 검색된 결과를 INSERT INTO를 사용하여 다른 테이블에 삽입하는 명령입니다.'),
('DB_CONST', '45. 다음 중 기본 테이블에 있는 튜플들 중에서 특정 튜플의 내용을 변경할 때 사용하는 명령문은?', 'INSERT', 'DELETE', 'UPDATE', 'DROP', 3, '데이터의 내용을 갱신(변경)할 때는 UPDATE 문을 사용합니다.'),
('DB_CONST', '46. 다음 표와 같은 판매실적 테이블에서 서울지역에 한하여 판매액 내림차순으로 지점명과 판매액을 출력하고자 한다. 가장 적절한 SQL 구문은?', 'SELECT 지점명, 판매액 FROM 판매실적 WHERE 도시="서울" ORDER BY 판매액 DESC;', 'SELECT 지점명, 판매액 FROM 판매실적 ORDER BY 판매액 DESC;', 'SELECT 지점명, 판매액 FROM 판매실적 WHERE 도시="서울" ORDER BY 판매액 ASC;', 'SELECT * FROM 판매실적 WHEN 도시="서울" ORDER BY 판매액 DESC;', 1, 'WHERE절로 조건을 지정하고, ORDER BY 필드명 DESC로 내림차순 정렬합니다.'),
('DB_CONST', '47. 트랜잭션을 수행하는 도중 장애로 인해 손상된 데이터베이스를 손상되기 이전의 정상적인 상태로 복구시키는 작업은?', 'Recovery', 'Restart', 'Commit', 'Abort', 1, '데이터베이스를 장애 이전의 일관된 상태로 복구하는 것을 회복(Recovery)이라고 합니다.'),
('DB_CONST', '48. 다음 조건을 모두 만족하는 정규형은? (-도메인 원자값 -모든 필드 완전함수종속 -모든 결정자가 후보키)', 'BCNF', '제1정규형', '제2정규형', '제3정규형', 1, '모든 결정자가 후보키인 정규형은 BCNF(보이스-코드 정규형)입니다.'),
('DB_CONST', '49. 관계 데이터베이스의 정규화에 대한 설명으로 옳지 않은 것은?', '정규화를 거치지 않으면 여러 가지 상이한 종류의 정보를 하나의 릴레이션으로 표현하여 이상 현상이 발생할 수 있다.', '하나의 종속성이 하나의 릴레이션에 표현될 수 있도록 릴레이션을 합병(Combination)하는 과정이다.', '이상(Anomaly) 현상은 데이터들 간에 존재하는 함수적 종속이 하나의 원인이 될 수 있다.', '정규화가 잘못되면 데이터의 불필요한 중복이 야기되어 문제를 유발할 수 있다.', 2, '정규화는 릴레이션을 합병하는 것이 아니라 더 작은 단위로 분해(Decomposition)하는 과정입니다.'),
('DB_CONST', '50. 분산 데이터베이스의 투명성(Transparency)에 해당하지 않는 것은?', 'Location Transparency', 'Replication Transparency', 'Failure Transparency', 'Media Access Transparency', 4, '분산 DB의 4대 투명성은 위치, 복제, 병행, 장애 투명성입니다.'),
('DB_CONST', '51. 스토리지의 종류 중 DAS(Direct Attached Storage)에 대한 설명으로 옳지 않은 것은?', '서버와 저장장치를 전용 케이블로 직접 연결하는 방식이다.', '저장 데이터가 적고 공유가 필요 없는 환경에 적합하다.', '네트워크를 통해 파일에 직접 접근할 수 있다.', '초기 구축 비용 및 유지보수 비용이 저렴하다.', 3, '네트워크를 통해 파일 수준으로 접근하는 것은 NAS(Network Attached Storage)의 특징입니다.'),
('DB_CONST', '52. 다음 SQL문의 실행 결과는? (김수철 학생의 학과 조회)', '데이터베이스', 'AI응용', 'AI분석', '전기과', 4, '서브쿼리 결과 김수철의 학번은 1004이며, 학과 테이블에서 1004번의 학과는 ''전기과''입니다.'),
('DB_CONST', '53. 정보 보안을 위한 접근통제 정책 종류에 해당하지 않는 것은?', '정책적 접근통제(PAC)', '임의 접근통제(DAC)', '강제 접근통제(MAC)', '역할기반 접근통제(RBAC)', 1, '주요 접근통제 모델은 DAC, MAC, RBAC 세 가지입니다.'),
('DB_CONST', '54. 다음 두 릴레이션에서 외래키로 사용된 것은? (과목, 수강 테이블)', '수강번호', '과목번호', '학번', '과목명', 2, '수강 테이블의 과목번호는 과목 테이블의 기본키를 참조하고 있으므로 외래키입니다.'),
('DB_CONST', '55. 데이터베이스에서 병행제어의 목적으로 틀린 것은?', '시스템 활용도 최대화', '사용자에 대한 응답시간 최소화', '데이터베이스 공유 최소화', '데이터베이스 일관성 유지', 3, '병행제어는 여러 트랜잭션이 데이터베이스를 최대한 공유할 수 있도록 하는 것이 목적입니다.'),
('DB_CONST', '56. 관계 대수 일반 집합 연산자 중 결과 카디널리티가 두 릴레이션 중 작은 것보다 크지 않은 연산자는?', '합집합', '교집합', '차집합', '교차곱', 2, '교집합은 공통된 튜플만 반환하므로 결과가 두 집합 중 작은 쪽의 크기를 넘을 수 없습니다.'),
('DB_CONST', '57. 관계형 데이터베이스의 제약 조건 중 개체 무결성과 참조 무결성을 설명하는 표의 빈칸 내용으로 부적합한 것은?', '테이블', '속성, 튜플', '기본키', '외래키', 1, '개체 무결성의 제약 대상은 릴레이션(테이블) 자체가 아니라 튜플 또는 속성 단위로 적용됩니다.'),
('DB_CONST', '58. 집합 A의 각 원소는 집합 B의 원소 여러 개와 대응하고, 집합 B의 각 원소는 집합 A의 원소 한 개와 대응하는 관계는?', '일 대 일', '일 대 다', '다 대 다', '다 대 일', 2, '문제의 조건은 A(1) : B(N)의 관계이므로 ''일 대 다'' 관계입니다.'),
('DB_CONST', '59. CREATE TABLE 시 참조 테이블의 튜플이 삭제되더라도 기본 테이블의 튜플은 삭제되지 않도록 지정하는 옵션은?', 'ON DELETE CASCADE', 'ON DELETE SET NULL', 'ON DELETE NO ACTION', 'ON DELETE SET DEFAULT', 3, 'NO ACTION 옵션은 참조하는 데이터가 있어도 연쇄 삭제를 방지하거나 거절합니다.'),
('DB_CONST', '60. 집합 연산자에 대한 설명으로 틀린 것은?', 'UNION은 두 릴레이션의 교차곱을 수행하기 때문에 공통 튜플 수와 관계가 없다.', 'UNION ALL은 중복된 행을 포함하여 두 SELECT문의 조회 결과를 모두 출력한다.', '두 SELECT문의 조회 결과 중 공통된 행만 출력하는 집합 연산자는 INTERSECT이다.', 'EXCEPT는 두 릴레이션의 차집합 연산을 수행하기 때문에 첫 번째 릴레이션의 튜플보다 많은 수의 튜플이 출력될 수 없다.', 1, 'UNION은 합집합 연산이지 교차곱(Cartesian Product) 연산이 아닙니다.');
INSERT INTO CATEGORY (CATEGORY_CD, CATEGORY_NM) VALUES ('TEST', '테스트');
