INSERT INTO QUIZ_MASTER (CATEGORY_CD, QUESTION, OPTION_1, OPTION_2, OPTION_3, OPTION_4, ANSWER, EXPLANATION, LEVEL, RANDOM_YN) VALUES
('TEST', '3번이 정답', '1', '2', '3', '4', 3, NULL, 1, 'Y');